import { useNavigate } from "react-router-dom";
import VideoCallView from "@/pages/VideoCall/VideoCallView";
import LiveRoomTopPanel from "@/components/LiveRoomTopPanel";
import webCallManager from "@/utils/webCallManager";
import { CallState } from "@/types/call";
import { useCallback, useEffect, useRef } from "react";
import { useCall } from "@/hooks/useCall";
import { eventBus, EventNames } from "../../utils/eventBus";
import { showExitCallModal } from "@/components/ExitCallModal";
import { getReturnPath } from "@/utils/callReturnPath";

const TAG = "VideoCall";

const VideoCall = () => {
  const navigate = useNavigate();
  const { callState } = useCall();

  const pageStartTime = useRef(Date.now());
  const is15HintShown = useRef(false);
  const is30HintShown = useRef(false);

  /** 获取当前通话时长（秒） */
  const getCallDuration = useCallback(() => {
    const session = webCallManager.connectSession;
    if (!session?.callBeginTime) return 0;
    return Math.round((Date.now() - session.callBeginTime) / 1000);
  }, []);

  /** 获取倒计时时间（页面打开后 5 秒内不允许挂断） */
  const getCountdownTime = useCallback(() => {
    const elapsed = Math.round((Date.now() - pageStartTime.current) / 1000);
    return Math.max(0, 5 - elapsed);
  }, []);

  /** 执行挂断并返回 */
  const handleHangup = useCallback(async () => {
    await webCallManager.hangup();
    eventBus.emit(EventNames.CALL_USER_HANGUP);
    navigate(getReturnPath(), { replace: true });
  }, [navigate]);

  /** 继续通话 */
  const handleContinue = useCallback(() => {
    is30HintShown.current = false;
    is15HintShown.current = false;
  }, []);

  // ==================== 主入口：点击关闭按钮 ====================

  const handleClose = useCallback(() => {
    const duration = getCallDuration();

    // 通话 ≤ 28s → 15秒违规警告
    if (duration <= 28 && !is15HintShown.current) {
      is15HintShown.current = true;
      showExitCallModal({
        isUserHangup: true,
        is30Hint: false,
        is15Hint: true,
        callTypeLabel: "video",
        countdownTime: getCountdownTime(),
        onEndCall: handleHangup,
        onContinue: handleContinue,
      });
      return;
    }

    // 28s < 通话 < 30s → 30秒挽留
    if (duration > 28 && duration < 30 && !is30HintShown.current) {
      is30HintShown.current = true;
      showExitCallModal({
        isUserHangup: true,
        is30Hint: true,
        is15Hint: false,
        callTypeLabel: "video",
        countdownTime: getCountdownTime(),
        onEndCall: handleHangup,
        onContinue: handleContinue,
      });
      return;
    }

    // 兜底 → 普通确认挂断
    showExitCallModal({
      isUserHangup: true,
      is30Hint: false,
      is15Hint: false,
      callTypeLabel: "video",
      countdownTime: getCountdownTime(),
      onEndCall: handleHangup,
      onContinue: handleContinue,
    });
  }, [getCallDuration, getCountdownTime, handleHangup, handleContinue]);

  // ==================== 通话状态监听 ====================

  useEffect(() => {
    console.log(TAG, callState);
    if (callState === CallState.Incoming) {
      console.log(" webCallManager.accept();==>");
      webCallManager.accept();
    }

    if (!webCallManager?.connectSession?.roomId) {
      navigate(getReturnPath(), { replace: true });
    }
  }, [callState]);

  useEffect(() => {
    return () => {
      webCallManager.hangup();
    };
  }, []);

  return (
    <div className="fixed inset-0 bg-black">
      <VideoCallView />
      <LiveRoomTopPanel onClickClose={handleClose} isAlwaysShow={true} />
    </div>
  );
};

export default VideoCall;
